class FileSystem:
    def __init__(self):
        self.paths = {"": -1}
    def createPath(self, path, value):
        if not path or path == "/" or path in self.paths: return False
        parent = path[:path.rfind('/')]
        if parent not in self.paths: return False
        self.paths[path] = value
        return True
    def get(self, path):
        return self.paths.get(path, -1)

def solveFileSystem(commands, args):
    fs = FileSystem()
    res = []
    for cmd, arg in zip(commands, args):
        if cmd == "FileSystem": res.append(None)
        elif cmd == "createPath": res.append(fs.createPath(arg[0], arg[1]))
        elif cmd == "get": res.append(fs.get(arg[0]))
    return res

